  public static final DeferredRegister.Blocks REGISTRY = DeferredRegister.createBlocks(DoomsdayDecorationMod.MODID);

  private static BlockBehaviour.Properties props() {
    return BlockBehaviour.Properties.of()
        .strength(1.0F, 10.0F)
        .noOcclusion()
        .isSuffocating((s, l, p) -> false)
        .isViewBlocking((s, l, p) -> s.isSolidRender(l, p))
        .isRedstoneConductor((s, l, p) -> false);
  }

  private static <T extends Block> DeferredBlock<T> register(String id, Supplier<? extends T> supplier) {
    return REGISTRY.register(id, supplier);
  }

